import json, os

def merge_comm(path, updates):
    data = json.load(open(path)) if os.path.exists(path) else {}
    for ch, verses in updates.items():
        if ch not in data:
            data[ch] = {}
        for v, html in verses.items():
            if v not in data[ch]:
                data[ch][v] = html
    json.dump(data, open(path, 'w'), ensure_ascii=False, indent=2)
    print(f"wrote {path}")

BOOK = "2samuel"
PATH = f"data/commentary/mkt-original/{BOOK}.json"

# 2 Samuel 24: David's census, divine anger, Gad's three options (sword/famine/plague),
# the plague and its cessation, Araunah's threshing floor, David's altar.
# The chapter closing the Succession Narrative; v1 and v14 and v18 and v24 already present.
# mkt-original linguistic commentary.

CH24 = {
    # v1, v14, v18, v24 already present
    "2": "<p><em>Vayomer ha-melekh el-Yoav sar-ha-chayil asher-itto: shut na be-khol shivtei Yisra'el mi-Dan ve-ad Be'ersheva u-phiqdu et-ha-am</em> — David's census command to Joab: <em>shut na</em> (please go around, traverse — <em>shut</em> in the Qal means to go about, roam) through all the tribes of Israel from Dan to Beersheba. The formula <em>mi-Dan ve-ad Be'ersheva</em> (from Dan to Beersheba) is the standard delimitation of the full extent of Israelite territory — Dan in the north (Tel Dan, near the Hermon headwaters), Beersheba in the south (the Negev border). The purpose: <em>u-phiqdu et-ha-am</em> (muster/number the people) — the Piel of <em>paqad</em> (to number, muster, attend to) for a military census.</p>",
    "3": "<p><em>Vayomer Yoav el-ha-melekh: ve-yoseph YHWH elohekha el-ha-am ka-hem ve-kha-hem me'ah pe'amim</em> — Joab's objection: may YHWH multiply the people a hundredfold. <em>Ve-einei adoni ha-melekh ro'ot</em> (and the eyes of my lord the king see it) — the wish that David would live to see the multiplication. <em>Ve-adoni ha-melekh lammah chaphetz ba-davar ha-zeh</em> — why does my lord the king desire this thing? Joab's rare public opposition to a royal command signals the unusual nature of the census; the Deuteronomistic narrator frames his objection as the voice of wisdom the king overrides.</p>",
    "4": "<p><em>Va-yechezeq devar ha-melekh el-Yoav ve-al-sarei he-chayil</em> — &ldquo;the king's word prevailed (<em>chazaq</em>, was strong) against Joab and the commanders of the army.&rdquo; <em>Va-yetze Yoav ve-sarei he-chayil lifnei ha-melekh li-phqod et-am Yisra'el</em> — Joab and the army commanders went out from the king's presence to muster Israel. The departure formula marks the execution of a reluctant command — Joab obeys but the narrator has already signaled the objection.</p>",
    "5": "<p><em>Va-ya'averu et-ha-Yarden va-yachanu be-Aro'er li-ymin ha-ir asher be-tokh ha-nachal ha-Gad ve-el-Ya'azer</em> — the census route begins by crossing the Jordan and camping at Aroer — the traditional southern boundary of Reuben and Gad east of the Jordan (Josh 13:9, 16). <em>Li-ymin ha-ir asher be-tokh ha-nachal</em> (to the right of the city that is in the middle of the wadi) specifies Aroer's position in the Arnon canyon. The systematic geographic progression of the census reflects the administrative reality of counting by region.</p>",
    "6": "<p><em>Va-yavo'u ha-Gil'adah ve-el-eretz Tachtim Chodshi</em> — they came to Gilead and to the land of Tahtim-hodshi (a problematic place name — the MT is uncertain; the LXX reads &ldquo;the land of the Hittites, to Kadesh&rdquo;). The census route circles through the Transjordanian territories (Gilead, Jazer), then swings north toward Dan and Sidon, west through the fortified cities of the Hivites and Canaanites, and finally south through Judah to Beersheba — a complete geographic circuit of the entire realm.</p>",
    "7": "<p><em>Va-yavo'u el-mivtzar Tzor ve-khol-arei ha-Chivvi ve-ha-Kena'ani</em> — the census reaches the fortress of Tyre (<em>mivtzar Tzor</em>, the fortified city of Tyre) and all the cities of the Hivites and Canaanites. The inclusion of these non-Israelite territories in the census reflects the extent of Davidic administrative reach — the subjugated peoples of Canaan were subject to David's governance. <em>Va-yetze'u el-negev Yehudah Be'er-sheva</em> — they went out to the Negev of Judah, to Beersheba — completing the circuit at the southern boundary point.</p>",
    "8": "<p><em>Va-yashuttu be-khol-ha-aretz va-yavo'u mi-qetz tish'ah chadashim ve-esrim yom Yerushalaim</em> — they traversed the whole land and came back to Jerusalem at the end of nine months and twenty days. The duration of the census circuit — nine months and twenty days — is the longest time-period specified for a single administrative task in the Succession Narrative, underlining the scope of the undertaking.</p>",
    "9": "<p><em>Va-yitten Yoav et-mispar miphqad-ha-am el-ha-melekh</em> — Joab gave the number of the mustering (<em>mispar miphqad-ha-am</em>) to the king. The double census vocabulary — <em>mispar</em> (number, count) and <em>miphqad</em> (mustering, from <em>paqad</em>) — signals a formal administrative report. The total: <em>va-yehi Yisra'el shemoneh me'ot eleph ish-chayil sholelh cherev ve-ish Yehudah chamesh-me'ot eleph ish</em> — Israel 800,000 able-bodied men (men of valor drawing the sword) and Judah 500,000 men. These numbers are likely administrative totals or hyperbolic summaries rather than literal headcounts.</p>",
    "10": "<p><em>Va-yakh lev David oto acharei-khen sapher et-ha-am</em> — &ldquo;And David's heart struck him (<em>vayakh lev David oto</em>) after he had numbered the people.&rdquo; The idiom <em>nakhah lev</em> (the heart strikes) denotes conscience-stricken conviction — it appears in 1 Sam 24:6 (David's heart struck him after cutting Saul's robe) and here. <em>Va-yomer David el-YHWH: chatati me'od asher asiti</em> — &ldquo;and David said to YHWH: I have sinned greatly in what I have done.&rdquo; The confession formula <em>chatati me'od</em> (I have sinned greatly) echoes his confession in ch. 12 (<em>chatati le-YHWH</em>). <em>Ve-attah YHWH ha'aver na et-avon avdekha ki nivalti me'od</em> — &ldquo;please take away the iniquity of your servant, for I have acted very foolishly (<em>nivalti</em>, Niphal of <em>naval</em>, to be foolish/worthless).&rdquo;</p>",
    "11": "<p><em>Va-yaqom David ba-boqer u-devar YHWH hayah el-Gad ha-navi chozeh David lemor</em> — YHWH's word came to Gad the prophet, &ldquo;seer of David&rdquo; (<em>chozeh David</em>). The title <em>chozeh</em> (seer, from <em>chazah</em>, to see/envision) is the designation of a prophet who receives visions — distinct from <em>ro'eh</em> (general seer) and <em>navi</em> (spokesman). <em>Chozeh David</em> marks Gad as David's personal court prophet — cf. 2 Chr 29:25, where Gad appears as the king's seer who established liturgical arrangements.</p>",
    "12": "<p><em>Halokh ve-dibbart el-David: koh amar YHWH shalosha anokhi notel aleikha</em> — YHWH's offer of three options: <em>shalosha anokhi notel aleikha</em> (three things I am lifting/offering to you). The verb <em>natal</em> (to lift, offer, present) with the Qal participle creates a present-tense offer — the three punishments are being held out as options. <em>Bchar-lekha achat meyhem ve-e'eseh-lakh</em> — choose one of them for yourself and I will do it to you.</p>",
    "13": "<p><em>Va-yavo Gad el-David va-yagged lo va-yomer lo: hata'voa-lekha sheva shanim raav be-artzekha</em> — Gad's presentation of the three options: (1) seven years of famine (<em>raav</em>); (2) three months of flight from your enemies (<em>nos lifnei tzarrekha</em>); (3) three days of plague (<em>dever</em>) in the land. The LXX reads three years for the famine (matching 1 Chr 21:12); the MT's seven years aligns with the seven-year famine pattern elsewhere (Gen 41; 2 Kgs 8:1). The three options span the three categories of covenant curse: famine, sword (military defeat), and pestilence — the classic triad of Deuteronomic judgment (Deut 28; Lev 26; Jer 14:12; Ezek 14:21).</p>",
    "15": "<p><em>Va-yitten YHWH dever be-Yisra'el min-ha-boqer ve-ad et-mo'ed</em> — YHWH sent plague (<em>dever</em>) in Israel from morning until the appointed time. <em>Va-yamot min-ha-am mi-Dan ve-ad Be'ersheva shivim eleph ish</em> — and seventy thousand men of the people died from Dan to Beersheba. The geographic formula <em>mi-Dan ve-ad Be'ersheva</em> (from Dan to Beersheba) is the same as the census formula of v. 2 — the punishment covers the same extent as the sin. The 70,000 dead creates an appalling reversal: the census that counted the people to strengthen royal power results in the reduction of the people.</p>",
    "16": "<p><em>Va-yishlach et-yado ha-malakh Yerushalaim le-shacheta</em> — &ldquo;And the angel stretched out his hand toward Jerusalem to destroy it (<em>le-shacheta</em>, Hiphil infinitive of <em>shachat</em>).&rdquo; <em>Va-yinnachem YHWH el-ha-ra'ah</em> — &ldquo;and YHWH relented (<em>yinnachem</em>, Niphal of <em>nacham</em>) concerning the evil (<em>ha-ra'ah</em>).&rdquo; The verb <em>nacham</em> (to relent, be comforted, change course) in YHWH's response is the same verb used for YHWH relenting from destruction elsewhere (Exod 32:14, Jonah 3:10, Amos 7:3). <em>Ha-malakh asher-hishchit ba-am</em> (the angel who was destroying among the people) — beside the threshing floor of Araunah the Jebusite.</p>",
    "17": "<p><em>Vayomer David el-YHWH be-re'otho et-ha-malakh ha-makkeh ba-am</em> — David's intercessory prayer when he saw the angel striking the people. <em>Vayomer: hinneh anokhi chatati ve-anokhi he'eveti</em> — &ldquo;Behold, I sinned and I did wickedly (<em>he'eveti</em>, Hiphil of <em>avah</em>, to act perversely/crookedly).&rdquo; <em>Ve-elleh ha-tson mah asu</em> — &ldquo;and these, the sheep, what have they done?&rdquo; The shepherd-and-flock metaphor — the king as shepherd whose guilt falls on the innocent flock — is the most direct statement of vicarious suffering in the Succession Narrative. David's identification of himself as the guilty party and the people as innocent sheep applies the covenant-kingship logic: the shepherd bears responsibility for the flock's condition.</p>",
    "19": "<p><em>Va-ya'al David ki-devar Gad asher tzivvah YHWH</em> — David went up according to the word of Gad, which YHWH commanded. The obedience formula — <em>ki-devar Gad asher tzivvah YHWH</em> (according to the word of Gad which YHWH commanded) — frames David's action as prophetically directed compliance rather than royal initiative. The sanctuary-founding narrative that follows (vv. 18–25) is the theological climax of 2 Samuel: the site of David's altar is the future site of Solomon's Temple.</p>",
    "20": "<p><em>Va-yashqeph Araunah va-yar et-ha-melekh ve-avadav ovirim alav</em> — Araunah looked out (<em>shaqaph</em>, to look down from a height) and saw the king and his servants crossing toward him. <em>Va-yetze Araunah va-yishtachu la-melekh appaiv artzah</em> — Araunah went out and prostrated himself before the king, faces to the ground. The prostration of the Jebusite threshing-floor owner before the king is both courtly convention and a recognition of David's royal authority over the city — Araunah's native city, which David conquered (5:6–9).</p>",
    "21": "<p><em>Vayomer Araunah: maddua va adoni ha-melekh el-avdo</em> — &ldquo;why has my lord the king come to his servant?&rdquo; <em>Va-yomer David: liqnot me-imkha et-ha-goren le-vnot mizbeach la-YHWH</em> — &ldquo;to buy (<em>qanah</em>) from you the threshing floor, to build an altar to YHWH.&rdquo; The verb <em>qanah</em> (buy, acquire — also to create/possess, as in Gen 14:19, YHWH as <em>qoneh shamayim va-aretz</em>) is the foundational act: the Temple site begins with a legitimate purchase, not royal confiscation. The contrast with Ahab's seizure of Naboth's vineyard (1 Kgs 21) is implicit: David buys what kings in the ancient Near East routinely took.</p>",
    "22": "<p><em>Vayomer Araunah el-David: yiqach va-ya'al adoni ha-melekh ha-tov be-einav</em> — &ldquo;let my lord the king take and offer up what seems good to him.&rdquo; Araunah offers everything: the oxen for burnt offerings (<em>olot</em>), the threshing sledges and the yokes of the oxen for wood. The generosity of the Jebusite's offer is genuine — he provides both the sacrifice animals and the wood from his agricultural equipment, giving up his livelihood for the king's worship.</p>",
    "23": "<p><em>Ha-kol natan Araunah ha-melekh la-melekh</em> — &ldquo;all this Araunah the king gives to the king.&rdquo; The unusual double use of <em>ha-melekh</em> (the king) — <em>Araunah ha-melekh</em> (Araunah the king) and <em>la-melekh</em> (to the king) — is textually difficult. <em>Ha-melekh</em> applied to Araunah may be an honorific title (&ldquo;Araunah the noble/lord&rdquo;) or a textual variant. The Septuagint reads &ldquo;Ornan gave all these things to the king&rdquo; without the title. <em>Va-yomer Araunah el-ha-melekh: YHWH elohekha yirtzekha</em> — and Araunah said to the king: may YHWH your God accept you (<em>yirtzekha</em>, Qal jussive of <em>ratzah</em>, to accept favorably, be pleased with).</p>",
    "25": "<p><em>Va-yiven sham David mizbeach la-YHWH va-ya'al olot u-shelamim</em> — &ldquo;And David built there an altar to YHWH and offered burnt offerings (<em>olot</em>) and peace offerings (<em>shelamim</em>).&rdquo; The <em>olah</em> (whole burnt offering) represents total consecration to YHWH; the <em>shelamim</em> (peace offering, from <em>shalom</em>) represents the restored covenant relationship between God and people. The double offering — total devotion and covenant peace — is the theological summary of the chapter and of 2 Samuel: David the sinful king seeks and receives restoration through sacrifice. <em>Va-ye'ater YHWH la-aretz va-te'atzar ha-magepha me-al Yisra'el</em> — &ldquo;and YHWH responded to the entreaty for the land and the plague was stopped from Israel.&rdquo; The verb <em>ya'ater</em> (Niphal of <em>atar</em>, to be entreated, to respond to entreaty) — the same verb used for the resolution of the Gibeonite blood-guilt in 21:14 — ties the two appendix narratives together: both crises required covenant atonement; both were resolved by divine response to human sacrifice. The threshing floor of Araunah becomes the site of Solomon's Temple (2 Chr 3:1) — the final altar of David's reign prefigures the permanent dwelling place of YHWH's Name.</p>",
}

